#include<bits/stdc++.h>
using namespace std;

char a[10000];

int main()
{
	int len,i,j,s=0,maxn=0,mina=9999,b=0,c=0;
	fgets(a,10000,stdin);
	len=strlen(a);
	for(i=0;i<=len-1;i++)
	{
		if(a[i]!=' '&&a[i]!=','&&a[i]!='.')
		{
			s++;
		}
		else if(s>0)
		{
			if(s>maxn)
			{
				maxn=s;
				b=i-s;
			}
			if(mina>s)
			{
				mina=s;
				c=i-s;
			}
			s=0;
		}
	}
	for(i=b;i<=b+maxn-1;i++)
	{
		printf("%c",a[i]);
	}
	printf("\n");
	for(j=c;j<=c+mina-1;j++)
	{
		printf("%c",a[j]);
	}
	return 0;
}
